const input = (items[0] && items[0].json) ? items[0].json : {};

const now = new Date();
const stamp = now.toISOString().replace(/[-:.TZ]/g, '').slice(0, 14);
const executionId = ($execution && $execution.id) ? String($execution.id) : String(input.execution_id || 'manual');
const runId = 'run-' + executionId + '-' + stamp;

function parseBool(value, fallback = false) {
  if (value === true || value === false) return value;
  const normalized = String(value == null ? '' : value).toLowerCase();
  if (normalized === 'true') return true;
  if (normalized === 'false') return false;
  return fallback;
}

function parseNumber(value, fallback) {
  const num = Number(value);
  return Number.isFinite(num) ? num : fallback;
}

const pinnedModel = 'qwen3.5:27b';
const requestedModel = String(input.model || $env.OLLAMA_MODEL || pinnedModel).trim();
if (requestedModel !== pinnedModel) {
  throw new Error('Ungueltiges Modell: ' + requestedModel + '. Erlaubt ist nur ' + pinnedModel + '.');
}

const workflowDir = input.workflow_dir || $env.OBSIDIAN_WORKFLOW_DIR || 'Marketing/Social-Media/Beitraege/Workflow';

const context = {
  run_id: runId,
  execution_id: executionId,
  workflow_key: 'run',
  workflow_name: 'Ablauf automatisch steuern',
  created_at: now.toISOString(),
  completed_at: null,
  status: 'running',

  topic_hint: String(input.topic || ''),
  model_primary: pinnedModel,
  model_used: pinnedModel,

  quality_gate: {
    min_quality_score: parseNumber($env.PIPELINE_MIN_QUALITY_SCORE, 70),
    min_evidence_refs: parseNumber($env.PIPELINE_MIN_EVIDENCE_REFS, 3),
    min_draft_body_len: parseNumber($env.PIPELINE_MIN_DRAFT_BODY_LEN, 180),
  },

  workflow_dir: workflowDir,
  workflow_results_dir: input.workflow_results_dir || $env.OBSIDIAN_WORKFLOW_RESULTS_DIR || (workflowDir + '/Ergebnisse'),
  workflow_detail_dir: input.workflow_detail_dir || $env.OBSIDIAN_WORKFLOW_DETAIL_DIR || (workflowDir + '/Ergebnisse/Laufdetails'),
  workflow_error_dir: input.workflow_error_dir || $env.OBSIDIAN_WORKFLOW_ERROR_DIR || (workflowDir + '/Ergebnisse/Fehlerdetails'),
  workflow_intermediate_dir: input.workflow_intermediate_dir || $env.OBSIDIAN_WORKFLOW_INTERMEDIATE_DIR || (workflowDir + '/Zwischenergebnisse'),
  workflow_prompts_dir: input.workflow_prompts_dir || $env.OBSIDIAN_WORKFLOW_PROMPTS_DIR || (workflowDir + '/Prompts'),

  workflow_runs_file: input.workflow_runs_file || $env.OBSIDIAN_WORKFLOW_RUNS_FILE || (workflowDir + '/Ergebnisse/00-Runs.md'),
  workflow_overview_file: input.workflow_overview_file || $env.OBSIDIAN_WORKFLOW_OVERVIEW_FILE || (workflowDir + '/Workflow Übersicht.md'),

  obsidian_rest_url: input.obsidian_rest_url || $env.OBSIDIAN_REST_URL || '',
  obsidian_rest_api_key: input.obsidian_rest_api_key || $env.OBSIDIAN_REST_API_KEY || '',
  allow_insecure_tls: parseBool(input.allow_insecure_tls, parseBool($env.OBSIDIAN_ALLOW_INSECURE_TLS, false)),

  prompts: {},
  model_trace: Array.isArray(input.model_trace) ? input.model_trace : [],
  stage_logs: Array.isArray(input.stage_logs) ? input.stage_logs : [],
  stage_summaries: Array.isArray(input.stage_summaries) ? input.stage_summaries : [],
  artifacts: (input.artifacts && typeof input.artifacts === 'object') ? input.artifacts : {},

  output_paths: (input.output_paths && typeof input.output_paths === 'object') ? input.output_paths : {},
  generated: (input.generated && typeof input.generated === 'object') ? input.generated : {},
};

return [{ json: context }];

const ctx = items[0].json;

if (!ctx.obsidian_rest_url || !ctx.obsidian_rest_api_key) {
  throw new Error('Missing OBSIDIAN_REST_URL or OBSIDIAN_REST_API_KEY');
}

const baseUrl = String(ctx.obsidian_rest_url).replace(/\/+$/, '');

function vaultUrl(path) {
  return baseUrl + '/vault/' + encodeURI(path);
}

async function obsidianGet(path) {
  return await this.helpers.httpRequest({
    method: 'GET',
    url: vaultUrl(path),
    headers: {
      Authorization: 'Bearer ' + ctx.obsidian_rest_api_key,
    },
    json: false,
    skipSslCertificateValidation: !!ctx.allow_insecure_tls,
  });
}

async function readRequiredTextFile(path) {
  try {
    const text = await obsidianGet.call(this, path);
    const normalized = String(text || '').trim();
    if (!normalized) {
      throw new Error('Prompt file is empty: ' + path);
    }
    return normalized;
  } catch (error) {
    const status = Number(
      (error && (error.statusCode || error.status || error.httpCode)) ||
      (error && error.response ? (error.response.status || error.response.statusCode || 0) : 0)
    );
    const isNotFound = status === 404 || /status code 404|\b404\b/i.test(String(error && error.message ? error.message : ''));
    if (isNotFound) {
      throw new Error('Required prompt file missing: ' + path);
    }
    throw new Error('Obsidian read failed for "' + path + '": ' + (error.message || 'unknown error'));
  }
}

const promptPaths = {
  recherche_signale: ctx.workflow_prompts_dir + '/recherche-signale.md',
  thema_pruefung: ctx.workflow_prompts_dir + '/thema-pruefung.md',
  entwurf_erstellung: ctx.workflow_prompts_dir + '/entwurf-erstellung.md',
  ton_kritik: ctx.workflow_prompts_dir + '/ton-kritik.md',
  strategie_kritik: ctx.workflow_prompts_dir + '/strategie-kritik.md',
  finale_kritik: ctx.workflow_prompts_dir + '/finale-kritik.md',
  kanal_linkedin: ctx.workflow_prompts_dir + '/kanal-linkedin.md',
  kanal_reddit: ctx.workflow_prompts_dir + '/kanal-reddit.md',
  schritt_zusammenfassung: ctx.workflow_prompts_dir + '/schritt-zusammenfassung.md',
};

for (const [key, path] of Object.entries(promptPaths)) {
  ctx.prompts[key] = await readRequiredTextFile.call(this, path);
}

return [{ json: ctx }];

const ctx = (items[0] && items[0].json) ? items[0].json : {};

return [{
  json: {
    run_id: ctx.run_id,
    execution_id: ctx.execution_id,
    status: ctx.status,
    topic: ctx.topic,
    model_used: ctx.model_used,
    run_detail_path: ctx.output_paths && ctx.output_paths.run_detail,
    workflow_runs_file: ctx.output_paths && ctx.output_paths.workflow_runs,
    workflow_intermediate_dir: ctx.output_paths && ctx.output_paths.workflow_intermediate_dir,
    workflow_intermediate_files: ctx.output_paths && ctx.output_paths.workflow_intermediate_files,
    workflow_overview_file: ctx.workflow_overview_file,
  },
}];
